faq-accordion:
{%- comment -%}
  Section: faq-accordion
  Type: faq
  Generated by: Section Conversion Agent v1.2
  Dawn version: 15.0
{%- endcomment -%}

{{ 'section-faq-accordion.css' | asset_url | stylesheet_tag }}

<div class="section-{{ section.id }} color-{{ section.settings.color_scheme }} gradient">
  <div class="page-width faq-accordion">
    {%- if section.settings.heading != blank -%}
      <div class="faq-accordion__header center">
        <{{ section.settings.heading_size }} class="faq-accordion__heading">
          {{ section.settings.heading | escape }}
        </{{ section.settings.heading_size }}>
        {%- if section.settings.subheading != blank -%}
          <div class="faq-accordion__subheading rte">
            {{ section.settings.subheading }}
          </div>
        {%- endif -%}
      </div>
    {%- endif -%}

    <div class="faq-accordion__items" role="list">
      {%- for block in section.blocks -%}
        {%- case block.type -%}
          {%- when 'faq_item' -%}
            <details
              class="faq-accordion__item accordion"
              id="Accordion-{{ section.id }}-{{ forloop.index }}"
              role="listitem"
              {{ block.shopify_attributes }}
            >
              <summary class="faq-accordion__summary accordion__title">
                <span class="faq-accordion__question h4">
                  {{ block.settings.question | escape }}
                </span>
                <span class="faq-accordion__icon">
                  {%- render 'icon-caret' -%}
                </span>
              </summary>
              <div class="faq-accordion__answer accordion__content rte">
                {{ block.settings.answer }}
              </div>
            </details>
        {%- endcase -%}
      {%- endfor -%}
    </div>
  </div>
</div>

{% style %}
  .section-{{ section.id }} {
    padding-top: {{ section.settings.padding_top }}px;
    padding-bottom: {{ section.settings.padding_bottom }}px;
  }

  .section-{{ section.id }} .faq-accordion__header {
    margin-bottom: 2.4rem;
  }

  .section-{{ section.id }} .faq-accordion__heading {
    margin: 0 0 0.8rem;
  }

  .section-{{ section.id }} .faq-accordion__subheading {
    margin: 0;
  }

  .section-{{ section.id }} .faq-accordion__item {
    border-bottom: 0.1rem solid rgba(var(--color-foreground), 0.08);
  }

  .section-{{ section.id }} .faq-accordion__item:first-child {
    border-top: 0.1rem solid rgba(var(--color-foreground), 0.08);
  }

  .section-{{ section.id }} .faq-accordion__summary {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1.6rem;
    padding: 1.6rem 0;
    cursor: pointer;
    list-style: none;
    font-family: var(--font-heading-family);
    line-height: 1.3;
  }

  .section-{{ section.id }} .faq-accordion__summary::-webkit-details-marker {
    display: none;
  }

  .section-{{ section.id }} .faq-accordion__summary:hover {
    opacity: 0.7;
  }

  .section-{{ section.id }} .faq-accordion__question {
    margin: 0;
    text-align: left;
  }

  .section-{{ section.id }} .faq-accordion__icon {
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    width: 2.4rem;
    height: 2.4rem;
  }

  .section-{{ section.id }} .faq-accordion__icon .icon-caret {
    width: 1.2rem;
    height: 1.2rem;
  }

  @media (prefers-reduced-motion: no-preference) {
    .section-{{ section.id }} .faq-accordion__icon .icon-caret {
      transition: transform 0.25s ease;
    }
  }

  .section-{{ section.id }} .faq-accordion__item[open] .faq-accordion__icon .icon-caret {
    transform: rotate(180deg);
  }

  .section-{{ section.id }} .faq-accordion__answer {
    padding: 0 0 1.6rem;
    font-family: var(--font-body-family);
    font-size: 1.4rem;
    line-height: 1.6;
  }

  @media (min-width: 750px) {
    .section-{{ section.id }} .faq-accordion__header {
      margin-bottom: 3.6rem;
    }

    .section-{{ section.id }} .faq-accordion__summary {
      padding: 2rem 0;
    }

    .section-{{ section.id }} .faq-accordion__answer {
      padding: 0 0 2rem;
      font-size: 1.6rem;
      max-width: 80%;
    }

    .section-{{ section.id }} .faq-accordion__items {
      max-width: 80rem;
      margin: 0 auto;
    }
  }
{% endstyle %}

