ingredients-system:
{%- comment -%}
  Section: ingredients-system
  Type: description
  Generated by: Section Conversion Agent v1.2
  Dawn version: 15.0
{%- endcomment -%}

{{ 'section-ingredients-system.css' | asset_url | stylesheet_tag }}

<div class="section-{{ section.id }} color-{{ section.settings.color_scheme }} gradient">
  <div class="ingredients-system page-width">
    {%- if section.settings.heading != blank -%}
      <div class="ingredients-system__header center">
        <{{ section.settings.heading_size }} class="ingredients-system__heading">
          {{ section.settings.heading | escape }}
        </{{ section.settings.heading_size }}>
        {%- if section.settings.subheading != blank -%}
          <div class="ingredients-system__subheading rte">
            {{ section.settings.subheading }}
          </div>
        {%- endif -%}
      </div>
    {%- endif -%}

    {%- if section.blocks.size > 0 -%}
      <ul class="ingredients-system__grid grid grid--2-col-tablet grid--4-col-desktop" role="list">
        {%- for block in section.blocks -%}
          {%- case block.type -%}
            {%- when 'ingredient_card' -%}
              <li class="ingredients-system__item grid__item" {{ block.shopify_attributes }}>
                <div class="ingredients-system__card" data-cascade style="--animation-order: {{ forloop.index }};">
                  <div class="ingredients-system__image-wrapper">
                    {%- if block.settings.image != blank -%}
                      {{
                        block.settings.image
                        | image_url: width: 600
                        | image_tag:
                          widths: '200, 300, 400, 600',
                          sizes: '(min-width: 990px) calc((100vw - 10rem) / 4), (min-width: 750px) calc((100vw - 10rem) / 2), calc(100vw - 4rem)',
                          class: 'ingredients-system__image',
                          loading: 'lazy',
                          alt: block.settings.image.alt | escape
                      }}
                    {%- else -%}
                      {{ 'image' | placeholder_svg_tag: 'placeholder-svg' }}
                    {%- endif -%}
                  </div>

                  <h3 class="ingredients-system__name h4">
                    {{ block.settings.name | escape }}
                  </h3>

                  {%- if block.settings.dosage != blank -%}
                    <p class="ingredients-system__dosage">
                      {{ block.settings.dosage | escape }}
                    </p>
                  {%- endif -%}

                  {%- if block.settings.description != blank -%}
                    <details class="ingredients-system__details" id="IngredientDetails-{{ section.id }}-{{ forloop.index }}">
                      <summary class="ingredients-system__summary">
                        <span class="ingredients-system__summary-text">
                          {{ block.settings.summary_label | default: 'Learn more' | escape }}
                        </span>
                        <span class="ingredients-system__chevron">
                          {% render 'icon-caret' %}
                        </span>
                      </summary>
                      <div class="ingredients-system__content rte">
                        {{ block.settings.description }}
                      </div>
                    </details>
                  {%- endif -%}
                </div>
              </li>
          {%- endcase -%}
        {%- endfor -%}
      </ul>
    {%- endif -%}
  </div>
</div>

{% style %}
  .section-{{ section.id }} {
    padding-top: {{ section.settings.padding_top }}px;
    padding-bottom: {{ section.settings.padding_bottom }}px;
  }

  .section-{{ section.id }} .ingredients-system__header {
    margin-bottom: 4rem;
  }

  .section-{{ section.id }} .ingredients-system__heading {
    margin: 0 0 1rem;
    font-family: var(--font-heading-family);
    font-weight: var(--font-heading-weight);
  }

  .section-{{ section.id }} .ingredients-system__subheading {
    max-width: 72rem;
    margin: 0 auto;
    color: rgba(var(--color-foreground), 0.75);
  }

  .section-{{ section.id }} .ingredients-system__grid {
    list-style: none;
    padding: 0;
    margin: 0;
    gap: 2rem;
  }

  .section-{{ section.id }} .ingredients-system__card {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    height: 100%;
    padding: 2.4rem 1.6rem;
    border-radius: var(--media-radius);
    border: 0.1rem solid rgba(var(--color-foreground), 0.08);
    background: rgba(var(--color-background), 1);
  }

  .section-{{ section.id }} .ingredients-system__image-wrapper {
    width: 8rem;
    height: 8rem;
    margin-bottom: 1.6rem;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .section-{{ section.id }} .ingredients-system__image {
    max-width: 100%;
    max-height: 100%;
    width: auto;
    height: auto;
    object-fit: contain;
  }

  .section-{{ section.id }} .ingredients-system__name {
    margin: 0 0 0.4rem;
    font-family: var(--font-heading-family);
    font-weight: var(--font-heading-weight);
  }

  .section-{{ section.id }} .ingredients-system__dosage {
    margin: 0 0 1.2rem;
    font-size: 1.3rem;
    color: rgba(var(--color-foreground), 0.6);
  }

  .section-{{ section.id }} .ingredients-system__details {
    width: 100%;
    margin-top: auto;
    border-top: 0.1rem solid rgba(var(--color-foreground), 0.08);
    padding-top: 1.2rem;
  }

  .section-{{ section.id }} .ingredients-system__summary {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.4rem;
    cursor: pointer;
    list-style: none;
    font-size: 1.3rem;
    color: rgba(var(--color-foreground), 0.75);
  }

  .section-{{ section.id }} .ingredients-system__summary::-webkit-details-marker {
    display: none;
  }

  .section-{{ section.id }} .ingredients-system__summary:focus-visible {
    outline: 0.3rem solid rgba(var(--color-foreground), 0.5);
    outline-offset: 0.3rem;
  }

  .section-{{ section.id }} .ingredients-system__chevron .icon {
    width: 1rem;
    height: 1rem;
  }

  .section-{{ section.id }} details[open] .ingredients-system__chevron .icon {
    transform: rotate(180deg);
  }

  .section-{{ section.id }} .ingredients-system__content {
    padding-top: 1rem;
    font-size: 1.4rem;
    text-align: left;
    color: rgba(var(--color-foreground), 0.75);
  }

  @media (prefers-reduced-motion: no-preference) {
    .section-{{ section.id }} .ingredients-system__chevron .icon {
      transition: transform 0.25s ease;
    }
  }

  @media screen and (min-width: 750px) {
    .section-{{ section.id }} .ingredients-system__image-wrapper {
      width: 10rem;
      height: 10rem;
    }
  }
{% endstyle %}

